CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;


DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260716103141_InitialCreate') THEN
    CREATE TABLE "tblMasterProduct" (
        "MasterProductId" bigint GENERATED BY DEFAULT AS IDENTITY,
        "Sku" character varying(80),
        "Upc" character varying(50),
        "ProductName" character varying(250) NOT NULL,
        "Description" text,
        "Category" character varying(120),
        "Brand" character varying(120),
        "ProductType" character varying(40),
        "Abv" numeric(4,2),
        "ContainerType" character varying(40),
        "Volume" character varying(30),
        "PackSize" integer,
        "Vintage" integer,
        "DefaultImageUrl" character varying(500),
        "IsActive" boolean NOT NULL DEFAULT TRUE,
        "CreatedAt" timestamp with time zone NOT NULL,
        "UpdatedAt" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_tblMasterProduct" PRIMARY KEY ("MasterProductId")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260716103141_InitialCreate') THEN
    CREATE TABLE "tblRetailer" (
        "RetailerId" bigint GENERATED BY DEFAULT AS IDENTITY,
        "Email" character varying(150) NOT NULL,
        "PasswordHash" character varying(255) NOT NULL,
        "BusinessName" character varying(150) NOT NULL,
        "ContactName" character varying(120),
        "Phone" character varying(30),
        "IsActive" boolean NOT NULL DEFAULT TRUE,
        "CreatedAt" timestamp with time zone NOT NULL,
        "UpdatedAt" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_tblRetailer" PRIMARY KEY ("RetailerId")
    );
    END IF;
END $EF$;

DO $EF$
BEGIN
