        "ContentId" bigint GENERATED BY DEFAULT AS IDENTITY,
        "RetailerId" bigint NOT NULL,
        "ContentType" smallint NOT NULL,
        "Name" character varying(150) NOT NULL,
        "MasterKey" character varying(500),
        "MediaVariants" jsonb,
        "ThumbnailKey" character varying(500),
        "DurationSeconds" integer,
        "FileSizeBytes" bigint,
        "ContentHash" character varying(64),
        "Version" integer NOT NULL DEFAULT 1,
        "IsActive" boolean NOT NULL DEFAULT TRUE,
        "CreatedAt" timestamp with time zone NOT NULL,
        "UpdatedAt" timestamp with time zone NOT NULL,
        CONSTRAINT "PK_tblContent" PRIMARY KEY ("ContentId"),
        CONSTRAINT "FK_tblContent_tblRetailer_RetailerId" FOREIGN KEY ("RetailerId") REFERENCES "tblRetailer" ("RetailerId") ON DELETE RESTRICT
    );
    END IF;
END $EF$;

